def pick_source_target_for_common_neighbors(edge_list):
    """
    Given an undirected edge list, return a single [source, target] pair (u, v)
    suitable for testing nx.common_neighbors(G, u, v).
    Preference: choose a pair that has at least one common neighbor (non-empty result).
    Fallback: return endpoints of the first edge if no such pair exists.
    """
    if not edge_list:
        raise ValueError("edge_list is empty; cannot generate a source-target pair.")

    # Build adjacency
    adj = {}
    for u, v in edge_list:
        if u == v:
            # Skip self-loops for the purpose of generating meaningful pairs
            adj.setdefault(u, set())
            continue
        adj.setdefault(u, set()).add(v)
        adj.setdefault(v, set()).add(u)

    # Try to find a pair (u, v) that has at least one common neighbor
    # Any node w with degree >= 2 yields such a pair by picking two of its neighbors.
    for w, nbrs in adj.items():
        if len(nbrs) >= 2:
            it = iter(nbrs)
            u = next(it)
            v = next(it)
            return [u, v]

    # Fallbacks
    # 1) Use the first non-self-loop edge if available
    for u, v in edge_list:
        if u != v:
            return [u, v]

    # 2) If only self-loops exist, we cannot form a valid distinct pair
    # Try to find two distinct nodes from adjacency keys (unlikely here)
    nodes = list(adj.keys())
    for i in range(len(nodes)):
        for j in range(i + 1, len(nodes)):
            if nodes[i] != nodes[j]:
                return [nodes[i], nodes[j]]

    raise ValueError("Cannot generate a valid [source, target] pair from the provided edge list.")
